+        .map_err(|err| format!("failed serializing dtype differential report: {err}"))?;
+    fs::write(&artifact_path, payload.as_bytes())
+        .map_err(|err| format!("failed writing {}: {err}", artifact_path.display()))?;
+
+    Ok(report)
+}
